import{_ as a,o as i,c as e,a as t}from"./chunks/framework.8tiMeCK-.js";const g=JSON.parse('{"title":"第 8 章 内核内存分配器：伙伴系统与 Slab","description":"","frontmatter":{},"headers":[],"relativePath":"notes/linux_kernel_programming/ch08.md","filePath":"notes/linux_kernel_programming/ch08.md","lastUpdated":null}'),l={name:"notes/linux_kernel_programming/ch08.md"};function n(r,s,o,d,h,p){return i(),e("div",null,[...s[0]||(s[0]=[t(`<h1 id="第-8-章-内核内存分配器-伙伴系统与-slab" tabindex="-1">第 8 章 内核内存分配器：伙伴系统与 Slab <a class="header-anchor" href="#第-8-章-内核内存分配器-伙伴系统与-slab" aria-label="Permalink to &quot;第 8 章 内核内存分配器：伙伴系统与 Slab&quot;">​</a></h1><h3 id="_8-0-引言-当内核开始管理内存" tabindex="-1">8.0 引言：当内核开始管理内存 <a class="header-anchor" href="#_8-0-引言-当内核开始管理内存" aria-label="Permalink to &quot;8.0 引言：当内核开始管理内存&quot;">​</a></h3><p>在之前的章节里，我们像拆钟表一样剖析了内核的内部架构和进程管理。现在，我们要触碰这个操作系统中最为敏感、也最核心的神经系统——<strong>内存管理</strong>。</p><p>对于驱动开发者来说，这往往是“噩梦”的开始。你写好了逻辑，注册了中断，看起来一切完美，但系统就是不定期地崩溃，或者运行一段时间后莫名其妙地变慢。很多时候，问题就出在内存分配的细节上：你在不知不觉中浪费了宝贵的物理内存，或者在错误的上下文中睡眠了。</p><p>Linux 内核的内存分配并不是简单的“给你一块地”。它分成了两个主要的层次：底层的 <strong>页面分配器</strong>，也就是我们要讲的伙伴系统；以及构建在其上的 <strong>Slab 分配器</strong>。理解这两者的工作原理，知道什么时候用哪个，能让你在代码审查时少掉几根头发。</p><p>这一章，我们不仅要讲 API 的使用，还要通过代码和内核日志，把那些藏在背后的、反直觉的内存浪费问题挖出来。</p><hr><h3 id="_8-1-内核内存分配器-是谁在掌管-ram" tabindex="-1">8.1 内核内存分配器：是谁在掌管 RAM？ <a class="header-anchor" href="#_8-1-内核内存分配器-是谁在掌管-ram" aria-label="Permalink to &quot;8.1 内核内存分配器：是谁在掌管 RAM？&quot;">​</a></h3><p>我们要解决的核心问题很简单：<strong>在内核里，内存是怎么分配和释放的？</strong></p><p>但这背后藏着一个很深的认知陷阱。如果你带着用户空间 <code>malloc()</code> 的直觉进入内核，你会摔得很惨。内核内存是物理连续的，是珍贵的，而且永远<strong>不会被换出到磁盘</strong>。</p><h4 id="_8-1-1-两大引擎-页面分配器与-slab-分配器" tabindex="-1">8.1.1 两大引擎：页面分配器与 Slab 分配器 <a class="header-anchor" href="#_8-1-1-两大引擎-页面分配器与-slab-分配器" aria-label="Permalink to &quot;8.1.1 两大引擎：页面分配器与 Slab 分配器&quot;">​</a></h4><p>你可以把内核的内存管理想象成一家大型建材超市。</p><ul><li><strong>页面分配器</strong>是那个开着叉车的大仓库管理员。他手里有一张清单，记录着所有成捆的木材（2 的幂次方大小的物理页块）。如果你需要 128 根木头，他会给你一捆 128 根的；如果没有，他会把一捆 256 根的锯成两半。他只处理这种大宗交易。他的算法叫<strong>伙伴系统</strong>。</li><li><strong>Slab 分配器</strong>则是仓库门口的零售柜台。他知道大家经常只需要几个钉子（小对象），没必要每次都去仓库里搬一整捆木头。于是他预先把一些木头拆好了，放在各种规格的盒子里。当你需要 20 个钉子时，他给你一个 32 个装的盒子，虽然多了一点点，但总比给你一整捆木头强。</li></ul><p>这就引出了一个关键点：<strong>Slab 分配器是活在页面分配器之上的</strong>。Slab 的“盒子”最终还是要找页面分配器要“整捆的木头”。但对我们开发者来说，知道用哪个柜台能省下不少麻烦。</p><h4 id="_8-1-2-内核内存的铁律-不可交换" tabindex="-1">8.1.2 内核内存的铁律：不可交换 <a class="header-anchor" href="#_8-1-2-内核内存的铁律-不可交换" aria-label="Permalink to &quot;8.1.2 内核内存的铁律：不可交换&quot;">​</a></h4><p>这里有一条必须刻在脑子里的规则：<strong>内核内存是不可交换的</strong>。</p><p>用户空间的程序可以用完物理内存，然后被内核扔到 swap 分区里去（也就是磁盘），以此腾出 RAM。但内核代码本身运行的数据结构——比如用来管理内存的数据结构——绝不能被扔出去。否则，当内核想要从磁盘把数据读回来时，它需要内存来操作，而内存管理代码却在磁盘上……这就像是你为了找眼镜而需要戴上眼镜一样，是个死锁。</p><p>所以，内核内存是常驻 RAM 的。这也意味着，<strong>浪费内核内存比浪费用户内存的代价要大得多</strong>。</p><hr><h3 id="_8-2-页面分配器-伙伴系统的奥秘" tabindex="-1">8.2 页面分配器：伙伴系统的奥秘 <a class="header-anchor" href="#_8-2-页面分配器-伙伴系统的奥秘" aria-label="Permalink to &quot;8.2 页面分配器：伙伴系统的奥秘&quot;">​</a></h3><p>让我们走进那间大仓库。页面分配器的核心数据结构是 <code>struct zone</code>，而在它里面，有一个数组 <code>free_area[MAX_ORDER]</code>。这就是我们要讲的“伙伴系统空闲链表”。</p><h4 id="_8-2-1-理解空闲链表的结构" tabindex="-1">8.2.1 理解空闲链表的结构 <a class="header-anchor" href="#_8-2-1-理解空闲链表的结构" aria-label="Permalink to &quot;8.2.1 理解空闲链表的结构&quot;">​</a></h4><p><code>MAX_ORDER</code> 是一个架构相关的常量，在 x86 和 ARM 上通常是 11。这意味着我们有 11 条链表（编号 0 到 10），每条链表上挂着不同大小的“内存块”。</p><ul><li><strong>Order 0</strong>: 挂着 1 页（4 KB）的块。</li><li><strong>Order 1</strong>: 挂着 2 页（8 KB）的块。</li><li><strong>Order 2</strong>: 挂着 4 页（16 KB）的块。</li><li>...</li><li><strong>Order 10</strong>: 挂着 1024 页（4 MB）的块。</li></ul><p>所有的块都是<strong>物理连续</strong>的。这就是为什么分配器叫“伙伴系统”：如果你有一个 Order N 的块，把它切成两半，这两个 Order N-1 的块就是“伙伴”。如果它们都空闲了，它们就会重新合并成一个 Order N 的块。这就是“反碎片化”的魔法。</p><p>你可以通过 <code>/proc/buddyinfo</code> 这张“仓库账本”看到当前的库存：</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">$</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> cat</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /proc/buddyinfo</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">Node</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> 0,</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> zone</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">      DMA</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">      1</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">      1</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">      1</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">      0</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">      1</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">      1</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">      1</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">      0</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">      1</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">      1</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">      1</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">Node</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> 0,</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> zone</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">    DMA32</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">   3551</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">   1542</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">    476</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">    255</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">    158</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">     77</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">     41</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">     21</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">     11</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">      3</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">      0</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br></div></div><p>每一列数字对应的就是 Order 0 到 Order 10 上空闲块的数量。如果你在 Order 10 那一列看到 0，那就说明系统里已经找不到哪怕一块 4 MB 的连续物理内存了。</p><h4 id="_8-2-2-算法的实际运作-一个分配请求的一生" tabindex="-1">8.2.2 算法的实际运作：一个分配请求的一生 <a class="header-anchor" href="#_8-2-2-算法的实际运作-一个分配请求的一生" aria-label="Permalink to &quot;8.2.2 算法的实际运作：一个分配请求的一生&quot;">​</a></h4><p>假设你的驱动请求 128 KB 的内存。算一下，128 KB / 4 KB = 32 页。32 是 2 的 5 次方。所以分配器会去 Order 5 的链表上找。</p><ol><li><strong>如果有货</strong>：直接拿走。结束。</li><li><strong>如果没货</strong>：去 Order 6 找。如果 Order 6 有一个 256 KB 的块，分配器会把它切成两半（变成两个 128 KB 的伙伴）。</li><li><strong>处理多余部分</strong>：其中一半给你（满足请求），另一半挂回 Order 5 的链表上，留着下次用。</li></ol><p>听起来很完美，对吧？但这里有一个巨大的坑，叫做<strong>内部碎片</strong>。</p><h4 id="_8-2-3-踩坑现场-内部碎片的陷阱" tabindex="-1">8.2.3 踩坑现场：内部碎片的陷阱 <a class="header-anchor" href="#_8-2-3-踩坑现场-内部碎片的陷阱" aria-label="Permalink to &quot;8.2.3 踩坑现场：内部碎片的陷阱&quot;">​</a></h4><p>假设你需要 132 KB 的内存。 分配器一看：132 KB 不是 2 的幂。下一个能装下它的“盒子”是 Order 7 的块，也就是 256 KB。 结果：你申请了 132 KB，内核却给了你 256 KB。<strong>剩下的 124 KB 就这么浪费了</strong>。</p><p>这就是“锯木头”的代价。如果你只需要稍微超过 128 KB 的一点点，仓库管理员也会被迫去锯一捆 256 KB 的木头给你。</p><p>为了缓解这个问题，内核提供了一对 API：<code>alloc_pages_exact()</code> 和 <code>free_pages_exact()</code>。它们会聪明地多分配一点，然后把多余的部分“还”回去。虽然不能完全消除浪费，但能止血。</p><hr><h3 id="_8-3-使用页面分配器-api-与内核-交易" tabindex="-1">8.3 使用页面分配器 API：与内核“交易” <a class="header-anchor" href="#_8-3-使用页面分配器-api-与内核-交易" aria-label="Permalink to &quot;8.3 使用页面分配器 API：与内核“交易”&quot;">​</a></h3><p>现在我们要动手写代码了。页面分配器提供了一组 API，它们的名字里通常都有 <code>page</code> 或者 <code>free_page</code>。</p><h4 id="_8-3-1-核心速查表" tabindex="-1">8.3.1 核心速查表 <a class="header-anchor" href="#_8-3-1-核心速查表" aria-label="Permalink to &quot;8.3.1 核心速查表&quot;">​</a></h4><p>这些 API 是你在内核里做“大宗交易”的工具：</p><table tabindex="0"><thead><tr><th style="text-align:left;">API / 宏</th><th style="text-align:left;">功能</th><th style="text-align:left;">返回值</th></tr></thead><tbody><tr><td style="text-align:left;"><code>__get_free_page(gfp)</code></td><td style="text-align:left;">分配 1 页</td><td style="text-align:left;">内核逻辑地址</td></tr><tr><td style="text-align:left;"><code>__get_free_pages(gfp, order)</code></td><td style="text-align:left;">分配 $2^{order}$ 页</td><td style="text-align:left;">内核逻辑地址</td></tr><tr><td style="text-align:left;"><code>get_zeroed_page(gfp)</code></td><td style="text-align:left;">分配 1 页并<strong>清零</strong></td><td style="text-align:left;">内核逻辑地址</td></tr><tr><td style="text-align:left;"><code>alloc_page(gfp)</code></td><td style="text-align:left;">分配 1 页</td><td style="text-align:left;"><code>struct page *</code> 结构指针</td></tr><tr><td style="text-align:left;"><code>alloc_pages(gfp, order)</code></td><td style="text-align:left;">分配 $2^{order}$ 页</td><td style="text-align:left;"><code>struct page *</code> 结构指针</td></tr></tbody></table><p><strong>注意区别</strong>：<code>__get_free_page</code> 返回的是<strong>地址</strong>（你可以直接用），而 <code>alloc_page</code> 返回的是<strong>页描述符</strong>（<code>struct page</code>），你需要调用 <code>page_address()</code> 把它转换成地址才能用。这就像一个是直接给你钥匙，一个是给你登记卡让你去前台换钥匙。</p><h4 id="_8-3-2-释放内存-别搞砸了" tabindex="-1">8.3.2 释放内存：别搞砸了 <a class="header-anchor" href="#_8-3-2-释放内存-别搞砸了" aria-label="Permalink to &quot;8.3.2 释放内存：别搞砸了&quot;">​</a></h4><p>对应的释放 API 很简单：</p><div class="language-c vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">c</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">void</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> free_page</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">unsigned</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> long</span><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;"> addr</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">);</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">void</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> free_pages</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">unsigned</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> long</span><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;"> addr</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">unsigned</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> int</span><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;"> order</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">);</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">void</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> __free_pages</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">struct</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> page </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">*</span><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">page</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">unsigned</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> int</span><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;"> order</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">);</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br></div></div><p>这里有个经典的坑：如果你用 <code>alloc_page</code> 分配，得到了 <code>page</code> 指针，千万别把它当成长整型地址传给 <code>free_pages</code>，或者传给 <code>__free_pages</code> 的第一个参数时搞混了。一定要配对使用。</p><hr><h3 id="_8-4-gfp-标志-告诉内核你的底线" tabindex="-1">8.4 GFP 标志：告诉内核你的底线 <a class="header-anchor" href="#_8-4-gfp-标志-告诉内核你的底线" aria-label="Permalink to &quot;8.4 GFP 标志：告诉内核你的底线&quot;">​</a></h3><p>所有的分配函数里都有个叫 <code>gfp_mask</code> 的参数（比如 <code>GFP_KERNEL</code>，<code>GFP_ATOMIC</code>）。这不是摆设，它是你和内核签订的“生死契约”。</p><h4 id="_8-4-1-黄金法则-进程上下文-vs-原子上下文" tabindex="-1">8.4.1 黄金法则：进程上下文 vs 原子上下文 <a class="header-anchor" href="#_8-4-1-黄金法则-进程上下文-vs-原子上下文" aria-label="Permalink to &quot;8.4.1 黄金法则：进程上下文 vs 原子上下文&quot;">​</a></h4><p>这个规则你必须背下来，违反它系统就会死机或卡死：</p><ol><li><strong>GFP_KERNEL</strong>：你在<strong>进程上下文</strong>里（比如在模块的 <code>init</code> 函数，或者系统调用的实现里），而且<strong>允许睡眠</strong>。这是最常用的标志。它会告诉内核：“如果内存不够，你可以去回收内存，甚至去读写磁盘，慢慢来，我可以等。”</li><li><strong>GFP_ATOMIC</strong>：你在<strong>原子上下文</strong>里（比如中断处理函数 <code>ISR</code>，或者你正拿着自旋锁 <code>spinlock</code>）。这里<strong>绝对不能睡眠</strong>。你必须告诉内核：“必须现在给我，如果不行就直接失败返回，千万别尝试去调度或者 I/O。”</li></ol><p>如果你在持有自旋锁的时候用了 <code>GFP_KERNEL</code>，内核可能会尝试睡眠去换取内存，导致调度器混乱。这就是所谓的“在原子区睡眠”，后果通常是系统死锁或panic。</p><h4 id="_8-4-2-其他常用标志" tabindex="-1">8.4.2 其他常用标志 <a class="header-anchor" href="#_8-4-2-其他常用标志" aria-label="Permalink to &quot;8.4.2 其他常用标志&quot;">​</a></h4><ul><li><strong><code>__GFP_ZERO</code></strong>：这是个修饰符，通常与上面两个配合使用（<code>GFP_KERNEL | __GFP_ZERO</code>）。它告诉内核把分配来的内存清零。这是良好的编程习惯，可以防止信息泄露和未初始化内存漏洞。</li></ul><hr><h3 id="_8-5-slab-分配器-让小对象分配更高效" tabindex="-1">8.5 Slab 分配器：让小对象分配更高效 <a class="header-anchor" href="#_8-5-slab-分配器-让小对象分配更高效" aria-label="Permalink to &quot;8.5 Slab 分配器：让小对象分配更高效&quot;">​</a></h3><p>回到我们刚才的“建材超市”类比。如果你每次只需要几个字节（比如一个网络包的结构体 <code>sk_buff</code>），页面分配器那把大锯子就太笨重了。这时我们需要 Slab 分配器。</p><h4 id="_8-5-1-对象缓存与通用缓存" tabindex="-1">8.5.1 对象缓存与通用缓存 <a class="header-anchor" href="#_8-5-1-对象缓存与通用缓存" aria-label="Permalink to &quot;8.5.1 对象缓存与通用缓存&quot;">​</a></h4><p>Slab 分配器的设计初衷有两个：</p><ol><li><strong>对象缓存</strong>：内核里有很多常用的数据结构（比如 <code>task_struct</code>, <code>inode</code>, <code>dentry</code>）。它们被频繁地分配和释放。Slab 分配器会在系统初始化时预先创建这些对象的“缓存池”。当你需要 <code>task_struct</code> 时，直接从这个池子里拿一个现成的，用完扔回去。这比每次都去初始化一个新结构要快得多。</li><li><strong>通用缓存</strong>：对于我们没有特殊要求的常规内存分配，内核维护了一组 <code>kmalloc-N</code> 的缓存（比如 <code>kmalloc-8</code>, <code>kmalloc-16</code>, ... <code>kmalloc-8192</code>）。当你调用 <code>kmalloc(20, ...)</code> 时，内核会发现你需要的超过了 16 字节，于是直接给你一个 32 字节的 slab。</li></ol><h4 id="_8-5-2-核心速查表-kmalloc-与-kzalloc" tabindex="-1">8.5.2 核心速查表：kmalloc 与 kzalloc <a class="header-anchor" href="#_8-5-2-核心速查表-kmalloc-与-kzalloc" aria-label="Permalink to &quot;8.5.2 核心速查表：kmalloc 与 kzalloc&quot;">​</a></h4><p>这是你日常写驱动用得最多的 API：</p><div class="language-c vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">c</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">void</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> *</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">kmalloc</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">size_t</span><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;"> size</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">gfp_t</span><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;"> flags</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">);</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">void</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> *</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">kzalloc</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">size_t</span><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;"> size</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">gfp_t</span><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;"> flags</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">);</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">void</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> kfree</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">const</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> void</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> *</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">);</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br></div></div><ul><li><strong>kmalloc</strong>：返回未初始化的内存（内容是随机的，垃圾数据）。</li><li><strong>kzalloc</strong>：返回<strong>清零</strong>后的内存。<strong>推荐优先使用这个</strong>，省心又安全。</li><li><strong>kfree</strong>：释放内存。注意，传 <code>NULL</code> 给 <code>kfree</code> 是安全的，它什么都不做。</li></ul><p><strong>重要特性</strong>：Slab 分配出来的内存也是<strong>物理连续</strong>的，而且保证了<strong>CPU 缓存行对齐</strong>（Cache Line Aligned），这在高性能网络和存储驱动里至关重要。</p><hr><h3 id="_8-6-终极限制-kmalloc-的天花板" tabindex="-1">8.6 终极限制：kmalloc 的天花板 <a class="header-anchor" href="#_8-6-终极限制-kmalloc-的天花板" aria-label="Permalink to &quot;8.6 终极限制：kmalloc 的天花板&quot;">​</a></h3><p>既然 Slab 这么好用，那我是不是可以用 <code>kmalloc</code> 申请 100 MB 的内存？</p><p><strong>不行。</strong></p><p>回到那个建材超市的比喻。Slab 柜台虽然灵活，但它的存货（Slab 对象）最终也是从仓库（页面分配器）搬来的。而仓库里最大的那一单货物（<code>MAX_ORDER</code>）通常限制在 4 MB（1024 页）。</p><p>因此，<strong>kmalloc 的单次分配上限就是 4 MB</strong>。</p><p>如果你尝试分配超过这个大小的内存（比如 5 MB），<code>kmalloc</code> 会直接返回 <code>NULL</code>，内核甚至会打印警告信息，因为这种分配请求通常意味着设计上有问题。如果你真的需要那么大的连续物理内存，你应该考虑其他的 DMA 分配机制，或者重新设计你的数据结构，使用非连续的内存分页来处理。</p><hr><h3 id="_8-7-资源管理与技巧" tabindex="-1">8.7 资源管理与技巧 <a class="header-anchor" href="#_8-7-资源管理与技巧" aria-label="Permalink to &quot;8.7 资源管理与技巧&quot;">​</a></h3><p>最后，作为内核开发者，我们有几个小技巧能让代码更健壮。</p><ol><li><strong><code>devm_kzalloc</code></strong>：如果你在写设备驱动，尽量用这个 API。它是“资源托管”的。当你的驱动被卸载或者设备断开时，内核会<strong>自动</strong>帮你释放这块内存。你不用担心忘了 <code>kfree</code> 导致内存泄漏，这在错误处理路径里非常有用。</li><li><strong><code>kcalloc</code> 与 <code>kmalloc_array</code></strong>：如果你要分配一个数组，不要手算 <code>count * size</code>，直接用这两个 API。它们内部会检查整数溢出。防止你计算 <code>2000000000 * 2</code> 时溢出变成 0，导致分配极小的内存从而引发崩溃。</li><li><strong>注意对齐</strong>：Slab 分配器已经帮你做了缓存行对齐，所以尽量把频繁访问的数据结构成员放在结构体开头，以便它们落在同一个缓存行里，提高命中率。</li></ol><h2 id="本章回响" tabindex="-1">本章回响 <a class="header-anchor" href="#本章回响" aria-label="Permalink to &quot;本章回响&quot;">​</a></h2><p>回想一下本章开头提到的那个“噩梦”场景。现在你应该明白，为什么简单地“分配内存”在内核里这么复杂了。</p><p>内核的内存分配体系——从底层的页面分配器到上层的 Slab——本质上是在三个互相矛盾的目标之间做平衡：<strong>物理连续性</strong>、<strong>速度</strong>和<strong>碎片化</strong>。</p><ul><li>如果你需要<strong>物理连续</strong>的大块内存（比如 DMA），你必须直面伙伴系统的<strong>内部碎片</strong>问题。</li><li>如果你需要<strong>速度</strong>和小块内存，你依赖 Slab，但依然受限于底层伙伴系统的上限（4 MB）。</li><li>无论哪种选择，你都必须时刻清醒地知道自己在哪个<strong>上下文</strong>（GFP 标志），否则代价可能是整个系统的崩溃。</li></ul><p>下一章，我们将继续深入这个话题。你会发现，有时候连“物理连续”都不一定能保证，我们还需要处理更复杂的场景，比如 vmalloc 以及那个让所有服务器管理员都闻之色变的 OOM Killer。</p><hr><h2 id="练习题" tabindex="-1">练习题 <a class="header-anchor" href="#练习题" aria-label="Permalink to &quot;练习题&quot;">​</a></h2><h3 id="练习-1-application" tabindex="-1">练习 1：application <a class="header-anchor" href="#练习-1-application" aria-label="Permalink to &quot;练习 1：application&quot;">​</a></h3><p><strong>题目</strong>：假设你编写了一个网络设备驱动，其中断处理函数（ISR）需要为接收到的数据包分配一块物理连续的内存。已知该函数运行在原子上下文中，请问你应该使用以下哪个内存分配标志（GFP flag）？如果选错会有什么潜在后果？</p><details><summary>答案与解析</summary><p><strong>答案</strong>：应该使用 <code>GFP_ATOMIC</code>。如果使用 <code>GFP_KERNEL</code>，可能会导致系统死锁或崩溃。</p><p><strong>解析</strong>：1. <strong>概念应用</strong>：中断处理程序（ISR）运行在原子上下文（Atomic Context）中，在此上下文中不允许进程睡眠。 2. <strong>GFP 区别</strong>：<code>GFP_KERNEL</code> 是标准的分配标志，它允许内核在内存不足时通过回收内存或进行 I/O 操作来等待，这会导致调用进程睡眠。<code>GFP_ATOMIC</code> 则明确禁止分配器睡眠，如果内存不足，它会立即失败而不是等待。 3. <strong>后果分析</strong>：如果在持有自旋锁或处于中断上下文时调用 <code>GFP_KERNEL</code>，内核可能会尝试调度其他进程，导致死机或系统崩溃。因此，在原子上下文中必须使用 <code>GFP_ATOMIC</code>。</p></details><h3 id="练习-2-understanding" tabindex="-1">练习 2：understanding <a class="header-anchor" href="#练习-2-understanding" aria-label="Permalink to &quot;练习 2：understanding&quot;">​</a></h3><p><strong>题目</strong>：如果请求分配 132 KB 的物理连续内存，在标准的 Buddy System（伙伴系统）算法中（假设页大小为 4 KB），内核实际会分配多少内存？这种现象被称为什么？如果有 50 MB 的可用内存碎片化严重，可能会导致分配失败吗？</p><details><summary>答案与解析</summary><p><strong>答案</strong>：实际会分配 256 KB。这种现象称为内部碎片。是的，可能会失败。</p><p><strong>解析</strong>：1. <strong>计算逻辑</strong>：Buddy System 只能分配 $2^{order}$ 个页帧的内存块。132 KB 约等于 33 个页帧（132/4）。向上取最近的 2 的幂是 $2^6 = 64$ 个页帧，即 256 KB。 2. <strong>概念定义</strong>：请求的 132 KB 小于实际分配的 256 KB，剩余的 124 KB 无法被系统有效利用，这种浪费称为内部碎片。 3. <strong>思考/分析</strong>：虽然系统可能有 50 MB 的总空闲内存，但如果这 50 MB 是散落在低阶链表（如 order 0, 1, 2）中的碎片，无法凑出一个大的连续块（如 order 5 或更高），那么 256 KB 的分配请求就会失败。这就是 Buddy System 的局限性。</p></details><h3 id="练习-3-thinking" tabindex="-1">练习 3：thinking <a class="header-anchor" href="#练习-3-thinking" aria-label="Permalink to &quot;练习 3：thinking&quot;">​</a></h3><p><strong>题目</strong>：Linux 内核中有一个预分配的 Slab 缓存名为 <code>kmalloc-192</code>（在支持 <code>CONFIG_SLAB</code> 或 <code>CONFIG_SLUB</code> 的系统中）。请分析：为什么内核不直接使用伙伴系统来满足这种小于一页的小内存分配请求，而是维护这样一个 Slab 层？这样做对 CPU 缓存性能有什么潜在影响？</p><details><summary>答案与解析</summary><p><strong>答案</strong>：使用 Slab 层是为了减少内部碎片、提高分配速度并优化对象初始化成本。对 CPU 缓存的影响是：Slab 分配器通常会保证内存对齐到缓存行，从而提高缓存命中率。</p><p><strong>解析</strong>：1. <strong>架构设计</strong>：如果直接用 Buddy System 分配 192 字节，Buddy System 最小分配一页（4 KB），导致巨大的内部碎片（浪费 ~95%）。Slab 分配器将页“切分”成固定大小（如 192 字节）的槽位，极大提高了内存利用率。 2. <strong>性能考量</strong>：Buddy System 的分配/释放涉及复杂的链表操作和元数据更新，较慢。而 Slab 基于对象缓存，分配和释放通常只是简单的指针操作，速度极快。 3. <strong>缓存一致性</strong>：内核经常需要频繁分配/释放特定的数据结构（如 <code>task_struct</code>, <code>dentry</code>）。Slab 允许缓存这些对象，甚至允许初始化对象构造函数，避免重复初始化开销。 4. <strong>CPU 缓存对齐</strong>：Slab 分配器（特别是通用 <code>kmalloc</code> 缓存）通常会将分配的内存对齐到 CPU 缓存行（如 64 字节）。这避免了“False Sharing”（伪共享），即不同 CPU 核心修改同一缓存行上的不同变量导致的性能抖动，从而提升了多核系统下的性能。</p></details><hr><h2 id="要点提炼" tabindex="-1">要点提炼 <a class="header-anchor" href="#要点提炼" aria-label="Permalink to &quot;要点提炼&quot;">​</a></h2><p>Linux 内核内存管理分为两个核心层次：底层的<strong>伙伴系统</strong>负责管理物理连续的页框，适用于大块内存分配；上层的 <strong>Slab 分配器</strong>则构建在伙伴系统之上，通过缓存对象池来高效处理小块内存的频繁分配与释放。</p><p>伙伴系统将内存划分为 2 的幂次方大小的块，通过 <code>MAX_ORDER</code> 数组管理。虽然其“分裂与合并”机制能有效减少外部碎片，但极易产生<strong>内部碎片</strong>（如申请 132KB 却必须占用 256KB），因此在分配非 2 的幂次方大小的内存时需格外警惕浪费。</p><p>在内核中分配内存必须严格遵守<strong>GFP 标志的使用规则</strong>：在进程上下文中允许睡眠时使用 <code>GFP_KERNEL</code>，而在持有自旋锁或中断处理等<strong>原子上下文</strong>中必须使用 <code>GFP_ATOMIC</code>，否则会导致系统死锁或崩溃。</p><p>开发者应根据数据结构的大小选择合适的 API：<strong>大块内存</strong>（通常指多页）优先使用 <code>get_free_pages</code> 等页面分配器接口；<strong>小对象分配</strong>（小于一页）则应使用 <code>kmalloc</code> 或 <code>kzalloc</code>（推荐后者以自动清零），利用 Slab 缓存提高效率。</p><p>Slab 分配器虽然灵活，但其最大单次分配上限受限于底层伙伴系统的 <code>MAX_ORDER</code>（通常为 <strong>4 MB</strong>）。对于驱动开发，应善用 <code>devm_kzalloc</code> 等托管 API 以实现自动释放，并优先使用 <code>kmalloc_array</code> 防止数组分配时的整数溢出风险。</p>`,101)])])}const c=a(l,[["render",n]]);export{g as __pageData,c as default};
